parameters.text:
=You are a claim extraction specialist. Extract all verifiable factual claims from this content.

Content to analyze:
"{{ $json.body.content }}"

Verification depth: {{ $json.body.verification_depth || 'normal' }}

Extract claims that can be verified with external sources. Ignore opinions and subjective statements.

Respond with JSON:
{
  "claims": [
    {
      "id": 1,
      "text": "exact claim text",
      "type": "statistic|fact|date|quote|definition",
      "verifiability": "high|medium|low",
      "key_entities": ["entity1", "entity2"]
    }
  ],
  "total_claims": number,
  "content_type": "news|social|academic|other"
}

parameters.jsCode:
// Parse extracted claims
const response = $input.first().json;
const webhookInput = $('Webhook Trigger').first().json.body;

let claimsData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  claimsData = jsonMatch ? JSON.parse(jsonMatch[0]) : { claims: [] };
} catch (e) {
  claimsData = { claims: [], error: e.message };
}

return {
  claims: claimsData.claims || [],
  totalClaims: claimsData.total_claims || 0,
  contentType: claimsData.content_type || 'other',
  originalContent: webhookInput.content,
  verificationDepth: webhookInput.verification_depth || 'normal',
  requireCitations: webhookInput.require_citations !== false,
  extractorTokens: response.tokenUsage?.totalTokens || 0
};

parameters.text:
=You are a search query specialist. Generate effective search queries to verify these claims.

Claims to verify:
{{ JSON.stringify($json.claims, null, 2) }}

For each claim, generate 2-3 search queries that would help verify it.

Respond with JSON:
{
  "queries": [
    {
      "claim_id": 1,
      "queries": ["search query 1", "search query 2"],
      "wikipedia_titles": ["potential_article_title"],
      "expected_sources": ["wikipedia", "news", "official"]
    }
  ]
}

parameters.jsCode:
// Parse queries and prepare for verification
const response = $input.first().json;
const claimsData = $('Parse Claims').first().json;

let queriesData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  queriesData = jsonMatch ? JSON.parse(jsonMatch[0]) : { queries: [] };
} catch (e) {
  queriesData = { queries: [] };
}

// Merge claims with queries
const claimsWithQueries = claimsData.claims.map((claim, i) => {
  const queryInfo = queriesData.queries?.find(q => q.claim_id === claim.id) || {};
  return {
    ...claim,
    search_queries: queryInfo.queries || [claim.text],
    wikipedia_titles: queryInfo.wikipedia_titles || [],
    index: i
  };
});

return {
  claims: claimsWithQueries,
  totalClaims: claimsData.totalClaims,
  originalContent: claimsData.originalContent,
  requireCitations: claimsData.requireCitations,
  extractorTokens: claimsData.extractorTokens,
  queryTokens: response.tokenUsage?.totalTokens || 0
};

// Split claims for parallel verification
const data = $input.first().json;
const claims = data.claims || [];

// Create items for each claim (max 5 to avoid overwhelming APIs)
const items = claims.slice(0, 5).map(claim => ({
  json: {
    claim: claim,
    originalContent: data.originalContent,
    requireCitations: data.requireCitations
  }
}));

return items.length > 0 ? items : [{ json: { claim: null } }];

// Aggregate source data for this claim
const wikiData = $('Fetch Wikipedia').first().json;
const ddgData = $('Fetch DuckDuckGo').first().json;
const claimData = $('Split Claims').first().json;

return {
  claim: claimData.claim,
  sources: {
    wikipedia: {
      title: wikiData?.title || 'Not found',
      extract: wikiData?.extract || '',
      url: wikiData?.content_urls?.desktop?.page || null,
      found: !!wikiData?.extract
    },
    duckduckgo: {
      abstract: ddgData?.Abstract || '',
      abstractSource: ddgData?.AbstractSource || '',
      abstractURL: ddgData?.AbstractURL || '',
      relatedTopics: (ddgData?.RelatedTopics || []).slice(0, 3).map(t => t.Text || ''),
      found: !!ddgData?.Abstract
    }
  },
  requireCitations: claimData.requireCitations
};

parameters.text:
=You are a fact verification specialist. Verify this claim against the provided sources.

Claim to verify:
ID: {{ $json.claim?.id }}
Text: "{{ $json.claim?.text }}"
Type: {{ $json.claim?.type }}

Sources found:

Wikipedia:
- Title: {{ $json.sources.wikipedia.title }}
- Extract: {{ $json.sources.wikipedia.extract }}
- URL: {{ $json.sources.wikipedia.url }}

DuckDuckGo:
- Abstract: {{ $json.sources.duckduckgo.abstract }}
- Source: {{ $json.sources.duckduckgo.abstractSource }}
- Related: {{ $json.sources.duckduckgo.relatedTopics.join(', ') }}

Verify the claim and respond with JSON:
{
  "claim_id": {{ $json.claim?.id || 0 }},
  "original_claim": "claim text",
  "verdict": "TRUE|MOSTLY_TRUE|MIXED|MOSTLY_FALSE|FALSE|UNVERIFIABLE",
  "accuracy_score": 0-100,
  "supporting_evidence": ["evidence1"],
  "contradicting_evidence": ["evidence1"],
  "citations": [
    {
      "source": "Wikipedia|DuckDuckGo",
      "url": "source_url",
      "relevant_quote": "quote supporting verdict",
      "supports_claim": true|false|"partial"
    }
  ],
  "correction": "corrected statement if claim is false",
  "confidence": "high|medium|low"
}

IMPORTANT: Only cite sources that actually exist in the provided data. Do not fabricate citations.

parameters.jsCode:
// Parse verification result
const response = $input.first().json;
const sourceData = $('Aggregate Sources').first().json;

let verificationData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  verificationData = jsonMatch ? JSON.parse(jsonMatch[0]) : { verdict: 'UNVERIFIABLE' };
} catch (e) {
  verificationData = { verdict: 'UNVERIFIABLE', error: e.message };
}

return {
  verification: verificationData,
  claim: sourceData.claim,
  sources: sourceData.sources,
  tokens: response.tokenUsage?.totalTokens || 0
};

// Aggregate all verification results
const items = $input.all();
const prepData = $('Prepare Verification').first().json;

const verifications = items.map(item => item.json.verification).filter(v => v);
const totalVerificationTokens = items.reduce((sum, item) => sum + (item.json.tokens || 0), 0);

return {
  verifications: verifications,
  totalClaims: prepData.totalClaims,
  originalContent: prepData.originalContent,
  extractorTokens: prepData.extractorTokens,
  queryTokens: prepData.queryTokens,
  verificationTokens: totalVerificationTokens
};

// Parse cross-reference results
const response = $input.first().json;
const aggData = $('Aggregate Verifications').first().json;

let crossRefData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  crossRefData = jsonMatch ? JSON.parse(jsonMatch[0]) : { contradictions_found: [] };
} catch (e) {
  crossRefData = { contradictions_found: [], error: e.message };
}

return {
  verifications: aggData.verifications,
  crossReference: crossRefData,
  totalClaims: aggData.totalClaims,
  originalContent: aggData.originalContent,
  extractorTokens: aggData.extractorTokens,
  queryTokens: aggData.queryTokens,
  verificationTokens: aggData.verificationTokens,
  crossRefTokens: response.tokenUsage?.totalTokens || 0
};

// Format final output
const response = $input.first().json;
const crossRefData = $('Parse Cross-Reference').first().json;

let reportData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  reportData = jsonMatch ? JSON.parse(jsonMatch[0]) : { overall_accuracy_score: 50 };
} catch (e) {
  reportData = { overall_accuracy_score: 50, error: e.message };
}

const reportTokens = response.tokenUsage?.totalTokens || 0;

return {
  fact_check_report: {
    overall_accuracy_score: reportData.overall_accuracy_score,
    verdict_summary: reportData.verdict_summary,
    executive_summary: reportData.executive_summary,
    key_findings: reportData.key_findings,
    corrections_needed: reportData.corrections_needed,
    reliability_assessment: reportData.reliability_assessment,
    recommendations: reportData.recommendations,
    claims_analyzed: crossRefData.totalClaims,
    claims: crossRefData.verifications
  },
  contradictions_found: crossRefData.crossReference?.contradictions_found || [],
  sources_consulted: reportData.sources_consulted || ['Wikipedia', 'DuckDuckGo'],
  agent_stats: {
    claim_extractor_tokens: crossRefData.extractorTokens,
    query_generator_tokens: crossRefData.queryTokens,
    verification_agent_tokens: crossRefData.verificationTokens,
    cross_reference_tokens: crossRefData.crossRefTokens,
    report_generator_tokens: reportTokens,
    total_tokens: crossRefData.extractorTokens + crossRefData.queryTokens + crossRefData.verificationTokens + crossRefData.crossRefTokens + reportTokens,
    total_agents: 6
  },
  execution_id: $execution.id,
  workflow_id: $workflow.id,
  timestamp: new Date().toISOString()
};

// Placeholder for MAO telemetry - enable when MAO backend is running
// This node is disabled to avoid errors when no MAO instance is available
return $input.first().json;
